import unittest
from md_parser import extract_ids

class TestMdParser(unittest.TestCase):
    def test_basic_extract(self):
        md = '# Title\n<!-- id: abc-123 -->\nSome text.\n<!-- id: def-456 -->'
        self.assertEqual(extract_ids(md), ['abc-123', 'def-456'])
    def test_duplicates(self):
        md = '<!-- id: 1 -->\n<!-- id: 1 -->'
        self.assertEqual(extract_ids(md), ['1'])

if __name__ == '__main__':
    unittest.main()
